import React, { useEffect, useState } from 'react';
import { useParams, Link } from 'react-router-dom';

export default function GamePage() {
  const { slug } = useParams();
  const title = decodeSlug(slug);
  const [output, setOutput] = useState('');
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    // optionally fetch on mount — commented out by default
  }, [slug]);

  function decodeSlug(s) {
    if (!s) return '';
    return s.replace(/-/g, ' ').replace(/\b\w/g, c => c.toUpperCase());
  }

  async function runPython() {
    setLoading(true);
    setOutput('');
    try {
      const res = await fetch(`http://localhost:5000/run-python?game=${encodeURIComponent(title)}`);
      const text = await res.text();
      setOutput(text);
    } catch (e) {
      setOutput('Could not reach python runner. Start server.js at project root.');
    } finally {
      setLoading(false);
    }
  }

  return (
    <main style={{ padding: 20 }}>
      <nav style={{ marginBottom: 12 }}>
        <Link to="/games">← Back to games</Link>
      </nav>

      <h1>{title}</h1>

      <section style={{ maxWidth: 560 }}>
        <p>This is the page for <strong>{title}</strong>.</p>

        <div style={{ border: '1px solid #ddd', padding: 12, borderRadius: 8, marginTop: 12 }}>
          <p><strong>Python runner box</strong></p>
          <p>Click the button to run a tiny Python script that prints the game name.</p>
          <button onClick={runPython} disabled={loading} style={{ marginBottom: 8 }}>
            {loading ? 'Running…' : 'Run Python'}
          </button>
          <pre style={{ background: '#f6f6f6', padding: 8, borderRadius: 6 }}>{output}</pre>
        </div>
      </section>
    </main>
  );
}
